#include <stdio.h>
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
int main() {
    int T = 1;
    while (T--) {
        long long N, K, M;
        scanf("%lld %lld %lld", &N, &K, &M);
        long long res = 0;
        for (int i = 1; i <= N; i++) {
            if (gcd(i, N) == 1) {
                long long temp = 1;
                for (int j = 0; j < K; j++) {
                    temp = (temp * i) % M;
                }
                res = (res + temp) % M;
            }
        }
        printf("%lld\n", res);
    }
    return 0;
}

