import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = 1;
        while (T-- > 0) {
            long N = sc.nextLong();
            long K = sc.nextLong();
            long M = sc.nextLong();
            long res = 0;
            for (int i = 1; i <= N; i++) {
                if (gcd(i, (int)N) == 1) {
                    long temp = 1;
                    for (int j = 0; j < K; j++) {
                        temp = (temp * i) % M;
                    }
                    res = (res + temp) % M;
                }
            }
            System.out.println(res);
        }
    }
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}

